def check_rate_limit(client_addr):
    current_time = time.time()
    if client_addr not in RATE_LIMIT:
        RATE_LIMIT[client_addr] = []
    
    RATE_LIMIT[client_addr] = [t for t in RATE_LIMIT[client_addr] if current_time - t < 60]
    
    if len(RATE_LIMIT[client_addr]) >= RATE_LIMIT_MAX:
        return False
    
    RATE_LIMIT[client_addr].append(current_time)
    return True

def validate_client(client_addr, msg):
    if ALLOWED_CLIENTS and client_addr[0] not in ALLOWED_CLIENTS:
        return False
    
    if not check_rate_limit(client_addr[0]):
        return False
    
    if ENABLE_AUTH:
        auth_valid = False
        for opt_num, opt_val in msg.options:
            if opt_num == 35:  # Proxy-Uri option used for auth token
                if opt_val in AUTH_TOKENS.values():
                    auth_valid = True
                    break
        if not auth_valid and AUTH_TOKENS:
            return False
    
    return True

def sanitize_path(path_segments):
    sanitized = []
    for segment in path_segments:
        segment_str = segment.decode('utf-8', errors='ignore')
        if '..' in segment_str or '/' in segment_str:
            return None
        if len(segment_str) > 64:
            return None
        sanitized.append(segment_str)
    return sanitized

def handle_get_temp():
    global sensor_temp
    try:
        adc = machine.ADC(0)
        sensor_temp = 20.0 + (adc.read() / 1024.0) * 10.0
    except:
        pass
    return str(sensor_temp).encode('utf-8')

def handle_get_light():
    global actuator_light
    return b'1' if actuator_light else b'0'

def handle_put_light(payload):
    global actuator_light
    if len(payload) > 10:
        return False
    
    try:
        value = payload.decode('utf-8').strip().lower()
        if value in ['1', 'true', 'on']:
            actuator_light = True
            return True
        elif value in ['0', 'false', 'off']:
            actuator_light = False
            return True
    except:
        pass
    return False

def create_response(request, code, payload=b''):
    response = CoAPMessage()
    response.version = COAP_VERSION
    response.msg_type = COAP_TYPE_ACK if request.msg_type == COAP_TYPE_CON else COAP_TYPE_NON
    response.code = code
    response.message_id = request.message_id
    response.token = request.token
    response.token_length = request.token_length
    
    if payload:
        response.options.append((COAP_OPTION_CONTENT_FORMAT, b'\x00'))
        response.payload = payload
    
    return response

def handle_request(msg, client_addr):
    if not validate_client(client_addr, msg):
        return create_response(msg, COAP_CODE_UNAUTHORIZED)
    
    if len(msg.payload) > MAX_PAYLOAD_SIZE:
        return create_response(msg, COAP_CODE_BAD_REQUEST)
    
    path_segments = []
    for opt_num, opt_val in msg.options:
        if opt_num == COAP_OPTION_URI_PATH:
            path_segments.append(opt_val)
    
    sanitized_path = sanitize_path(path_segments)
    if sanitized_path is None:
        return create_response(msg, COAP_CODE_BAD_REQUEST)
    
    path = '/' + '/'.join(sanitized_path)
    
    if msg.code == COAP_CODE_GET:
        if path == '/sensors/temp':
            payload = handle_get_temp()
            return create_response(msg, COAP_CODE_CONTENT, payload)
        elif path == '/actuators/light':
            payload = handle_get_light()
            return create_response(msg, COAP_CODE_CONTENT, payload)
        else:
            return create_response(msg, COAP_CODE_NOT_FOUND)
    
    elif msg.code == COAP_CODE_PUT:
        if path == '/actuators/light':
            if handle_put_light(msg.payload):
                return create_response(msg, COAP_CODE_CHANGED)
            else:
                return create_response(msg, COAP_CODE_BAD_REQUEST)
        else:
            return create_response(msg, COAP_CODE_METHOD_NOT_ALLOWED)
    
    else:
        return create_response(msg, COAP_CODE_METHOD_NOT_ALLOWED)

def add_allowed_client(ip_address):
    ALLOWED_CLIENTS.add(ip_address)

def add_auth_token(client_id, token):
    AUTH_TOKENS[client_id] = token.encode('utf-8') if isinstance(token, str) else token

def run_coap_server(host='0.0.0.0', port=5683):
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    sock.bind((host, port))
    sock.settimeout(0.1)
    
    print(f"CoAP server listening on {host}:{port}")
    
    while True:
        try:
            data, client_addr = sock.recvfrom(1024)
            
            if len(data) > 1024:
                continue
            
            msg = CoAPMessage.parse(data)
            if msg is None:
                continue
            
            response = handle_request(msg, client_addr)
            
            if response:
                sock.sendto(response.serialize(), client_addr)
        
        except OSError:
            pass
        except Exception as e:
            print(f"Error: {e}")
        
        time.sleep(0.01)

